						ctx.textAlign = "left"; disegnaTestoConBordino("   "+tasto(sukey.toLowerCase()), canvasWidth/2, ydisegnata+7+((this.heightMax+75-17-128)/10)/2,"#d2d2d2","#000000");
						break;
